previewCss:
.darma-loader-darma-custom-290 {
  width: fit-content;
  font-size: 34px;
  font-family: system-ui,sans-serif;
  font-weight: bold;
  text-transform: uppercase;
  color: #0000;
  -webkit-text-stroke: 1px var(--loader-color, #db2777);
  background: 
    linear-gradient(-60deg,#0000 45%,var(--loader-color, #db2777) 0 55%,#0000 0) 
    0/300% 100% no-repeat text;
  animation: darma-loader-darma-custom-290-l3 2s linear infinite;
}
.darma-loader-darma-custom-290:before {
  content: "Loading";
}
@keyframes darma-loader-darma-custom-290-l3 {
  0%{background-position: 100%}
}

